SELECT module_name, version
FROM modules
ORDER BY module_name;

SELECT aggregator_name
FROM aggregators
WHERE aggregator_id = 0;

SELECT COUNT(module_id) AS module_count
FROM module_aggregator
WHERE aggregator_id = 1;

SELECT technology_type, MIN(created_at) AS min_creation_date
FROM technologies
GROUP BY technology_type;

SELECT jsr_number, jsr_status
FROM jsrs
WHERE jsr_status = 'Final';

SELECT COUNT(module_tech_id) AS mandatory_tech_count
FROM module_technology
WHERE module_id = 0 AND is_mandatory = 1;

SELECT module_name
FROM modules
ORDER BY module_name ASC;

SELECT COUNT(jsr_id) AS draft_jsr_count
FROM jsrs
WHERE jsr_status = 'Draft';
